    <!-- Floating notif badges placed BELOW frame so they don't overlap content.\r\n                 Subtle ribbon row that animates in to add liveliness. -->\r\n            <div class=\"auth-preview-floats\">\r\n              <div class=\"apf\"><span>▶</span><b>Trending</b></div>\r\n              <div class=\"apf\"><span>♥</span><b>+1.2k</b></div>\r\n              <div class=\"apf\"><span>👁</span><b>24.8k</b></div>\r\n              <div class=\"apf\"><span>💬</span><b>+58 new</b></div>\r\n            </div>\r\n\r\n            <!-- Screen indicator dots — Upload dot dihapus per user 2026-05-07 -->\r\n            <div class=\"auth-preview-dots\" id=\"authPreviewDots\">\r\n              <button type=\"button\" class=\"apd-dot apd-active\" data-go-screen=\"0\" aria-label=\"Home\"></button>\r\n              <button type=\"button\" class=\"apd-dot\" data-go-screen=\"1\" aria-label=\"Analytics\"></button>\r\n              <button type=\"button\" class=\"apd-dot\" data-go-screen=\"2\" aria-label=\"Pesan\"></button>\r\n            </div>\r\n          </div>\r\n\r\n        </div>\r\n      </div>\r\n\r\n      <!-- LEFT (ADMIN MODE): Brand showcase khusus admin — struktur sama dgn user -->\r\n      <div class=\"auth-left-admin\">\r\n        <div class=\"auth-brand\">\r\n          <div class=\"brand-logo big admin-p-logo\">\r\n            <svg viewBox=\"0 0 100 100\" fill=\"none\" xmlns=\"http://www.w3.org/2000/svg\">\r\n              <defs>\r\n                <!-- Chrome / silver iridescent — frosted satin metal vibe.\r\n                     White → light slate → cool grey → deep slate untuk efek\r\n                     metal mengkilap. LOGO IDENTITY — jangan ubah stop-color\r\n                     ini (user 2026-05-26). Kalau ada problem kontras dengan\r\n                     backdrop, fix lewat CSS drop-shadow outline, BUKAN ganti\r\n                     gradient stops. -->\r\n                <linearGradient id=\"plyl-au-admin\" x1=\"10%\" y1=\"0%\" x2=\"90%\" y2=\"100%\">\r\n                  <stop offset=\"0%\"   stop-color=\"#FFFFFF\"/>\r\n                  <stop offset=\"30%\"  stop-color=\"#FFFFFF\"/>\r\n                  <stop offset=\"70%\"  stop-color=\"#3C5078\"/>\r\n                  <stop offset=\"100%\" stop-color=\"#1C283C\"/>\r\n                </linearGradient>\r\n              </defs>\r\n              <!-- Modern stylized P — rounded bowl + stem, counter as evenodd hole -->\r\n              <path\r\n                fill=\"url(#plyl-au-admin)\"\r\n                fill-rule=\"evenodd\"\r\n                d=\"M 30 6 L 60 6 C 80 6 92 22 92 38 C 92 58 76 70 56 70 L 42 70 L 42 92 C 42 97 38 98 32 98 C 26 98 22 97 22 92 L 22 14 C 22 10 26 6 30 6 Z M 42 22 L 56 22 C 66 22 72 30 72 38 C 72 46 66 54 56 54 L 42 54 Z\"\r\n              />\r\n            </svg>\r\n          </div>\r\n          <div data-no-i18n>\r\n            <h1>Playly<span>.</span></h1>\r\n            <p>ADMIN CONTROL CENTER</p>\r\n          </div>\r\n        </div>\r\n\r\n        <div class=\"auth-showcase\">\r\n          <span class=\"admin-restricted-pill\" aria-label=\"Restricted access\">\r\n            <span class=\"arp-dot\"></span>\r\n            <span>Administrators Only</span>\r\n          </span>\r\n          <h2 data-i18n=\"auth.showcase.admin.title\">Manage the platform,<br/><span class=\"grad-text\" data-i18n=\"auth.showcase.admin.title.grad\">protect the community</span></h2>\r\n          <p data-i18n=\"auth.showcase.admin.desc\">Administrator dashboard for content moderation, real-time analytics, user management, ads, and platform revenue.</p>\r\n\r\n          <div class=\"auth-stats\">\r\n            <div><b data-stat-anim=\"ratio\" data-stat-final=\"24/7\">24/7</b><span data-i18n=\"auth.stat.monitoring\">Active monitoring</span></div>\r\n            <div><b data-stat-anim=\"percent\" data-stat-final=\"100%\">100%</b><span data-i18n=\"auth.stat.access\">Access control</span></div>\r\n            <div><b data-stat-anim=\"typewriter\" data-stat-final=\"Real\">Real</b><span data-i18n=\"auth.stat.analytics\">Time analytics</span></div>\r\n          </div>\r\n\r\n          <div class=\"auth-illus auth-illus-admin\">\r\n            <!-- Admin-specific motion: radar sweep + concentric scan rings +\r\n                 8 perimeter \"node\" dots + live monitoring ticker pill.\r\n                 Vibe: operational control center, beda dgn user yang lebih\r\n                 soft/playful. Pure CSS — no extra JS. -->\r\n            <div class=\"admin-radar\" aria-hidden=\"true\"></div>\r\n            <div class=\"admin-scan-rings\" aria-hidden=\"true\">\r\n              <span class=\"asr asr-1\"></span>\r\n              <span class=\"asr asr-2\"></span>\r\n              <span class=\"asr asr-3\"></span>\r\n            </div>\r\n            <div class=\"admin-nodes\" aria-hidden=\"true\">\r\n              <span class=\"adn adn-1\"></span>\r\n              <span class=\"adn adn-2\"></span>\r\n              <span class=\"adn adn-3\"></span>\r\n              <span class=\"adn adn-4\"></span>\r\n              <span class=\"adn adn-5\"></span>\r\n              <span class=\"adn adn-6\"></span>\r\n              <span class=\"adn adn-7\"></span>\r\n              <span class=\"adn adn-8\"></span>\r\n            </div>\r\n            <div class=\"floating-card f1\"><span>🛡</span><b data-i18n=\"auth.float.moderation\">Active moderation</b></div>\r\n            <div class=\"floating-card f2\"><span>📊</span><b>+12.4% growth</b></div>\r\n            <div class=\"floating-card f3\"><span>💰</span><b data-i18n=\"auth.float.revenue\">Revenue tracker</b></div>\r\n            <div class=\"play-orb auth-orb\">\r\n              <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M12 2 4 6v6c0 5 3.5 8.7 8 10 4.5-1.3 8-5 8-10V6l-8-4Z\"/><path d=\"m9 12 2 2 4-4\"/></svg>\r\n            </div>\r\n          </div>\r\n          <div class=\"admin-ticker\" aria-hidden=\"true\">\r\n            <span class=\"adt-dot\"></span>\r\n            <span class=\"adt-label\">MONITORING</span>\r\n            <b class=\"adt-count\">Live</b>\r\n            <span class=\"adt-suffix\">real-time</span>\r\n          </div>\r\n        </div>\r\n\r\n      </div>\r\n\r\n      <!-- RIGHT: Forms — MODAL POPUP (per request 2026-05-03 final).\r\n           Hidden by default; opened via topbar Sign In/Sign Up CTA atau plan picker.\r\n           Backdrop blur + centered card overlay seluruh viewport saat .show. -->\r\n      <div class=\"auth-right\" id=\"authModalWrap\">\r\n        <div class=\"auth-modal-backdrop\" data-modal-close></div>\r\n        <!-- Outer X close button removed per user request — Back button di\r\n             dalam card sudah handle navigasi balik ke landing/pick. -->\r\n        <button type=\"button\" class=\"auth-modal-close\" data-modal-close aria-label=\"Close\" hidden>✕</button>\r\n        <div class=\"auth-card\" id=\"authCard\" data-mode=\"user\" data-auth-state=\"landing\">\r\n          <!-- X close button INSIDE card — admin only via CSS, mirror style\r\n               dari .modal-close di Reset Password modal -->\r\n          <button type=\"button\" class=\"admin-card-close\" data-modal-close aria-label=\"Close\">✕</button>\r\n          <!-- Admin mode banner — hanya muncul di /admin. Layout-nya\r\n               mirror dari Reset Password modal: icon center → title center\r\n               → desc center. -->\r\n          <div class=\"admin-mode-banner\" id=\"adminModeBanner\" hidden>\r\n            <div class=\"amb-icon\">\r\n              <svg viewBox=\"0 0 100 100\" fill=\"none\" xmlns=\"http://www.w3.org/2000/svg\" aria-hidden=\"true\">\r\n                <defs>\r\n                  <linearGradient id=\"plyl-modal-admin\" x1=\"10%\" y1=\"0%\" x2=\"90%\" y2=\"100%\">\r\n                    <stop offset=\"0%\"   stop-color=\"#FFFFFF\"/>\r\n                    <stop offset=\"30%\"  stop-color=\"#FFFFFF\"/>\r\n                    <stop offset=\"70%\"  stop-color=\"#3C5078\"/>\r\n                    <stop offset=\"100%\" stop-color=\"#1C283C\"/>\r\n                  </linearGradient>\r\n                </defs>\r\n                <path\r\n                  fill=\"url(#plyl-modal-admin)\"\r\n                  fill-rule=\"evenodd\"\r\n                  d=\"M 30 6 L 60 6 C 80 6 92 22 92 38 C 92 58 76 70 56 70 L 42 70 L 42 92 C 42 97 38 98 32 98 C 26 98 22 97 22 92 L 22 14 C 22 10 26 6 30 6 Z M 42 22 L 56 22 C 66 22 72 30 72 38 C 72 46 66 54 56 54 L 42 54 Z\"\r\n                />\r\n              </svg>\r\n            </div>\r\n            <div class=\"amb-text\">\r\n              <b>Admin Panel Login</b>\r\n              <small>Platform administrators only · Restricted access<svg class=\"amb-shield\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\"><path d=\"M12 2 4 5v6c0 5 3.4 8.6 8 10 4.6-1.4 8-5 8-10V5z\"/><path d=\"m9 12 2 2 4-4\"/></svg></small>\r\n            </div>\r\n          </div>\r\n\r\n          <!-- User mode banner — login user (Masuk + Daftar).\r\n               Logo PLAIN (mono putih, tanpa gradient warna) per request user\r\n               2026-05-02. Cuma bentuk huruf P aja, tidak ada wine/cream gradient. -->\r\n          <div class=\"user-mode-banner\" id=\"userModeBanner\">\r\n            <div class=\"umb-icon\">\r\n              <svg viewBox=\"0 0 100 100\" fill=\"none\" xmlns=\"http://www.w3.org/2000/svg\" aria-hidden=\"true\">\r\n                <path\r\n                  fill=\"currentColor\"\r\n                  fill-rule=\"evenodd\"\r\n                  d=\"M 30 6 L 60 6 C 80 6 92 22 92 38 C 92 58 76 70 56 70 L 42 70 L 42 92 C 42 97 38 98 32 98 C 26 98 22 97 22 92 L 22 14 C 22 10 26 6 30 6 Z M 42 22 L 56 22 C 66 22 72 30 72 38 C 72 46 66 54 56 54 L 42 54 Z\"\r\n                />\r\n              </svg>\r\n            </div>\r\n            <div class=\"umb-text\">\r\n              <b data-i18n=\"auth.user.login\">Playly Creator Login</b>\r\n              <small data-i18n=\"auth.user.subtitle\">Start sharing your creation</small>\r\n            </div>\r\n          </div>\r\n\r\n          <!-- ============== PAYMENT STATUS BANNER ============== -->\r\n          <!-- Persistent across all auth states. Shows latest pending/approved/rejected\r\n               premium payment for any account on this device. Auto-polls when status\r\n               is pending. Populated dynamically by renderAuthPaymentBanner(). -->\r\n          <div class=\"auth-payment-banner\" id=\"authPaymentBanner\" hidden data-no-i18n>\r\n            <div class=\"apb-icon\" id=\"apbIcon\">⏳</div>\r\n            <div class=\"apb-content\">\r\n              <div class=\"apb-head\">\r\n                <strong class=\"apb-title\" id=\"apbTitle\">Pembayaran sedang diverifikasi</strong>\r\n                <span class=\"apb-status-badge\" id=\"apbStatusBadge\" data-status=\"pending\">Pending</span>\r\n              </div>\r\n              <div class=\"apb-meta\">\r\n                <code class=\"apb-code\" id=\"apbCode\">PLY-XXXXXXXX</code>\r\n                <span class=\"apb-divider\" aria-hidden=\"true\">·</span>\r\n                <span class=\"apb-plan\" id=\"apbPlan\">Playly Premium</span>\r\n                <span class=\"apb-divider\" aria-hidden=\"true\">·</span>\r\n                <span class=\"apb-amount\" id=\"apbAmount\">$9.99</span>\r\n              </div>\r\n              <p class=\"apb-desc\" id=\"apbDesc\">Admin sedang memeriksa pembayaranmu. Halaman ini auto-refresh setiap 5 detik.</p>\r\n            </div>\r\n            <div class=\"apb-actions\" id=\"apbActions\"></div>\r\n          </div>\r\n\r\n          <!-- ============== STATE: LANDING (default) ============== -->\r\n          <!-- Welcome card: brand intro + 2 big CTA buttons (Sign In / Sign Up).\r\n               Mau Sign In → langsung ke form. Mau Sign Up → ke plan picker dulu. -->\r\n          <div class=\"auth-state auth-state-landing\">\r\n            <h2 class=\"auth-welcome-title\">Welcome to Playly</h2>\r\n            <p class=\"auth-welcome-sub\">Choose how you want to continue</p>\r\n            <div class=\"auth-welcome-actions\">\r\n              <button type=\"button\" class=\"btn primary auth-welcome-btn\" data-go-state=\"signin\">\r\n                <span class=\"aw-ico\">→</span>\r\n                <span class=\"aw-text\">\r\n                  <strong>Sign In</strong>\r\n                  <small>Already have an account</small>\r\n                </span>\r\n              </button>\r\n              <button type=\"button\" class=\"btn ghost auth-welcome-btn\" data-go-state=\"signup-form\">\r\n                <span class=\"aw-ico\">＋</span>\r\n                <span class=\"aw-text\">\r\n                  <strong>Sign Up Free</strong>\r\n                  <small>New to Playly — pick a plan</small>\r\n                </span>\r\n              </button>\r\n            </div>\r\n            <p class=\"auth-welcome-foot\">Free includes 60 videos & 1 GB/month. Premium = unlimited.</p>\r\n          </div>\r\n\r\n          <!-- ============== STATE: SIGNUP PLAN PICKER ============== -->\r\n          <!-- User pilih dulu Gratis / Premium sebelum lihat form signup.\r\n               Semua teks Indonesia (produk Playly = Indonesian).\r\n               Ikon pakai inline SVG stroke-based supaya konsisten dgn ikon\r\n               nav/sidebar (bukan emoji raw). Harga USD dilengkapi ekuivalen\r\n               IDR via fmtUsdAsIdr() di script.js. -->\r\n          <div class=\"auth-state auth-state-signup-pick\">\r\n            <!-- Kembali button — pill compact di pojok kiri-atas card\r\n                 (absolute-positioned, lihat .auth-back-btn-pick di styles.css).\r\n                 \"Pilih paket kamu\" h3 dikembalikan + center per user\r\n                 2026-05-23. Sub-text \"Mulai gratis, upgrade kapan saja.\"\r\n                 tetap dihapus (redundant dengan auth header). -->\r\n            <button type=\"button\" class=\"auth-back-btn auth-back-btn-pick\" data-go-state=\"landing\" aria-label=\"Kembali\">\r\n              <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\"><path d=\"M15 6l-6 6 6 6\"/></svg>\r\n              <span>Kembali</span>\r\n            </button>\r\n            <h3 class=\"auth-pick-title auth-pick-title-center\" data-i18n=\"auth.tier.choose\">Pilih paket kamu</h3>\r\n            <!-- v555 (2026-05-26): subtitle lebih clear bahwa ini SIGNUP tier\r\n                 picker (Free vs Premium), bukan Premium variant picker\r\n                 (yang di-handle planPickerModal). Mengurangi confusion. -->\r\n            <p class=\"auth-pick-sub auth-pick-sub-center\">Daftar gratis selamanya — atau langsung pilih Premium.</p>\r\n            <div class=\"auth-pick-grid\">\r\n              <button type=\"button\" class=\"auth-pick-card\" data-pick-tier=\"free\">\r\n                <span class=\"apc-icon\" aria-hidden=\"true\">\r\n                  <!-- Leaf icon — stroke-based, match nav-icon style -->\r\n                  <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\r\n                    <path d=\"M11 20A7 7 0 0 1 4 13c0-5 4-9 9-9h7v7c0 5-4 9-9 9z\"/>\r\n                    <path d=\"M11 20c0-5 3-9 9-12\"/>\r\n                  </svg>\r\n                </span>\r\n                <strong>Gratis</strong>\r\n                <span class=\"apc-price\">$0<small>/bulan</small></span>\r\n                <span class=\"apc-price-idr\">≈ Rp 0</span>\r\n                <ul>\r\n                  <li>60 video unggah/bulan</li>\r\n                  <li>Penyimpanan 1 GB/bulan</li>\r\n                  <li>Kualitas 720p</li>\r\n                  <li>Dengan iklan sponsor</li>\r\n                </ul>\r\n                <span class=\"apc-cta\">Lanjut dengan Gratis →</span>\r\n              </button>\r\n              <button type=\"button\" class=\"auth-pick-card auth-pick-card-premium\" data-pick-tier=\"premium\">\r\n                <span class=\"apc-badge apc-badge-premium\">Paling Disarankan</span>\r\n                <span class=\"apc-icon\" aria-hidden=\"true\">\r\n                  <!-- Crown icon — stroke-based, match nav-icon style -->\r\n                  <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\">\r\n                    <path d=\"M3 7l4 5 5-7 5 7 4-5v11H3z\"/>\r\n                    <path d=\"M3 18h18\"/>\r\n                  </svg>\r\n                </span>\r\n                <strong>Premium</strong>\r\n                <span class=\"apc-price\">$9.99<small>/bulan</small></span>\r\n                <span class=\"apc-price-idr\">≈ Rp 148.500</span>\r\n                <ul>\r\n                  <li>Unggah tanpa batas</li>\r\n                  <li>Penyimpanan tanpa batas</li>\r\n                  <li>Streaming kualitas 4K</li>\r\n                  <li>Bebas iklan + dukungan prioritas</li>\r\n                </ul>\r\n                <span class=\"apc-cta\">Lanjut dengan Premium →</span>\r\n              </button>\r\n            </div>\r\n            <a href=\"#authPlansSection\" class=\"auth-pick-compare\" data-scroll-plans>Lihat perbandingan lengkap ↓</a>\r\n          </div>\r\n\r\n          <!-- ============== STATE: PLAN-AUTH-CHECK ============== -->\r\n          <!-- Shown when guest picks a premium plan — asks if they have an account -->\r\n          <div class=\"auth-state auth-state-plan-auth-check\">\r\n            <button type=\"button\" class=\"auth-back-btn\" id=\"pacBackBtn\">\r\n              <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M15 6l-6 6 6 6\"/></svg>\r\n              Kembali\r\n            </button>\r\n            <div class=\"pac-wrap\">\r\n              <span class=\"pac-plan-icon\" id=\"pacPlanIcon\" aria-hidden=\"true\">⭐</span>\r\n              <h3 class=\"pac-title\" data-i18n=\"auth.pac.title\">Sudah punya akun Playly?</h3>\r\n              <!-- Sub 1-line per user 2026-05-23: tidak ada <br>, full sentence. -->\r\n              <p class=\"pac-sub\" data-no-i18n>Masuk untuk lanjut ke pembayaran, atau daftar dulu kalau belum punya akun.</p>\r\n              <!-- Plan meta dipindah dekat tombol per user 2026-05-23\r\n                   (\"tukar susunan teks plan itu di dekat kolom\") — context\r\n                   pembayaran muncul tepat sebelum CTA. -->\r\n              <p class=\"pac-plan-meta\">Plan: <strong id=\"pacPlanName\">Monthly</strong> · <span id=\"pacPlanPrice\">$9.99/mo</span></p>\r\n              <div class=\"pac-btns\">\r\n                <button type=\"button\" class=\"btn primary pac-btn\" id=\"pacBtnHasAccount\" data-i18n=\"auth.pac.btn.yes\">Ya, masuk dulu →</button>\r\n                <button type=\"button\" class=\"btn ghost pac-btn\" id=\"pacBtnNoAccount\" data-i18n=\"auth.pac.btn.no\">Belum, daftar dulu →</button>\r\n              </div>\r\n            </div>\r\n          </div>\r\n\r\n          <!-- ============== STATE: FORMS (signin OR signup form) ============== -->\r\n          <div class=\"auth-state auth-state-forms\">\r\n            <span class=\"auth-tier-pill\" id=\"signupTierPill\" hidden>\r\n              <span id=\"signupTierPillIcon\">🌱</span>\r\n              <span>Paket dipilih: <b id=\"signupTierPillLabel\">Gratis</b></span>\r\n              <a href=\"#\" data-go-state=\"signup-pick\">ubah</a>\r\n            </span>\r\n\r\n          <div class=\"auth-tabs\" id=\"authTabs\">\r\n            <button class=\"active\" data-auth-tab=\"signin\" data-i18n=\"auth.signin\">Sign In</button>\r\n            <button data-auth-tab=\"signup\" data-i18n=\"auth.signup\">Sign Up</button>\r\n            <i class=\"auth-tab-pill\"></i>\r\n          </div>\r\n\r\n          <!-- SIGN IN FORM -->\r\n          <form class=\"auth-form active\" id=\"signinForm\" data-form=\"signin\" novalidate>\r\n            <div class=\"auth-lock-banner\" id=\"signinLockBanner\" hidden role=\"alert\">\r\n              <span class=\"auth-lock-icon\">🔒</span>\r\n              <div class=\"auth-lock-text\">\r\n                <strong data-i18n=\"auth.locked.title\">Account temporarily locked</strong>\r\n                <small><span data-i18n=\"auth.locked.try\">Try again in</span> <b id=\"signinLockCountdown\">--</b>. <span data-i18n=\"auth.forgot\">Forgot password?</span> <a href=\"#\" data-auth-action=\"forgot\" data-i18n=\"auth.reset.here\">Reset here</a>.</small>\r\n              </div>\r\n            </div>\r\n\r\n            <label class=\"auth-field\">\r\n              <span data-i18n=\"auth.email.username\">Email or Username</span>\r\n              <div class=\"input-wrap\">\r\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\"><rect x=\"3\" y=\"5\" width=\"18\" height=\"14\" rx=\"2\"/><path d=\"m3 7 9 6 9-6\"/></svg>\r\n                <input type=\"text\" name=\"email\" placeholder=\"you@email.com or username\" required autocomplete=\"username\"/>\r\n              </div>\r\n            </label>\r\n\r\n            <label class=\"auth-field\">\r\n              <span data-i18n=\"auth.password\">Password</span>\r\n              <div class=\"input-wrap\">\r\n                <svg viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\"><rect x=\"3\" y=\"11\" width=\"18\" height=\"11\" rx=\"2\"/><path d=\"M7 11V7a5 5 0 0 1 10 0v4\"/></svg>\r\n                <input type=\"password\" name=\"password\" placeholder=\"Min. 6 characters\" required autocomplete=\"current-password\"/>\r\n                <button type=\"button\" class=\"pw-toggle\" tabindex=\"-1\" aria-label=\"Tampilkan password\">\r\n                    <svg class=\"pw-eye pw-eye-open\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\"><path d=\"M2 12s3.5-7 10-7 10 7 10 7-3.5 7-10 7S2 12 2 12Z\"/><circle cx=\"12\" cy=\"12\" r=\"3\"/></svg>\r\n                    <svg class=\"pw-eye pw-eye-closed\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"1.8\" stroke-linecap=\"round\" stroke-linejoin=\"round\" aria-hidden=\"true\"><path d=\"m3 3 18 18\"/><path d=\"M10.6 10.7a2 2 0 0 0 2.7 2.7\"/><path d=\"M9.4 5.2A10.5 10.5 0 0 1 12 5c6.5 0 10 7 10 7-.5 1-1.2 1.9-2 2.7\"/><path d=\"M6.7 6.7C3.7 8.7 2 12 2 12s3.5 7 10 7c1.7 0 3.2-.5 4.6-1.2\"/></svg>\r\n                  </button>\r\n              </div>\r\n            </label>\r\n\r\n            <div class=\"auth-row\">\r\n              <label class=\"auth-check\">\r\n                <input type=\"checkbox\" checked/><i></i>\r\n                <span data-i18n=\"auth.remember\">Remember me</span>\r\n              </label>\r\n              <a href=\"#\" class=\"auth-link\" id=\"forgotPw\" data-i18n=\"auth.forgot\">Forgot password?</a>\r\n            </div>\r\n\r\n            <button type=\"submit\" class=\"btn primary auth-submit\">\r\n              <span data-i18n=\"auth.signin.now\">Sign In Now</span>\r\n            </button>\r\n\r\n            <p class=\"auth-switch\">\r\n              <span data-i18n=\"auth.no.account\">Don't have an account?</span> <a href=\"#\" data-auth-tab=\"signup\" data-i18n=\"auth.register.free\">Register free</a>\r\n            </p>\r\n          </form>\r\n\r\n          <!-- SIGN UP FORM -->\r\n          <form class=\"auth-form\" id=\"signupForm\" data-form=\"signup\" novalidate>\r\n            <h3 data-i18n=\"auth.create.title\">Create new account</h3>\r\n            <p class=\"auth-sub\" data-i18n=\"auth.create.sub\">Start sharing your creation today.</p>\r\n\r\n            <div class=\"signup-stepper\" id=\"signupStepper\" aria-hidden=\"true\">\r\n              <div class=\"step\" data-step=\"1\" data-status=\"active\">\r\n                <div class=\"step-circle\">\r\n                  <span class=\"step-num\">1</span>\r\n                  <svg class=\"step-check\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"3\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M5 13l4 4L19 7\"/></svg>\r\n                </div>\r\n                <span class=\"step-label\" data-i18n=\"auth.step.profile\">Profile</span>\r\n              </div>\r\n              <div class=\"step-line\" data-status=\"pending\"></div>\r\n              <div class=\"step\" data-step=\"2\" data-status=\"pending\">\r\n                <div class=\"step-circle\">\r\n                  <span class=\"step-num\">2</span>\r\n                  <svg class=\"step-check\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"3\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M5 13l4 4L19 7\"/></svg>\r\n                </div>\r\n                <span class=\"step-label\" data-i18n=\"auth.step.username\">Username</span>\r\n              </div>\r\n              <div class=\"step-line\" data-status=\"pending\"></div>\r\n              <div class=\"step\" data-step=\"3\" data-status=\"pending\">\r\n                <div class=\"step-circle\">\r\n                  <span class=\"step-num\">3</span>\r\n                  <svg class=\"step-check\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"3\" stroke-linecap=\"round\" stroke-linejoin=\"round\"><path d=\"M5 13l4 4L19 7\"/></svg>\r\n                </div>\r\n                <span class=\"step-label\" data-i18n=\"auth.step.account\">Account</span>\r\n              </div>\r\n              <div class=\"step-line\" data-status=\"pending\"></div>\r\n              <div class=\"step\" data-step=\"4\" data-status=\"pending\">\r\n                <div class=\"step-circle\">